import { useQuery } from '@tanstack/react-query';
import { fetchUserProfile, fetchPrimaryServices, fetchContentCards } from '@/services/mockApi';

export const useHomeData = () => {
  const userQuery = useQuery({ queryKey: ['user'], queryFn: fetchUserProfile });
  const servicesQuery = useQuery({ queryKey: ['primaryServices'], queryFn: fetchPrimaryServices });
  const contentQuery = useQuery({ queryKey: ['contentCards'], queryFn: fetchContentCards });

  return {
    user: userQuery.data,
    services: servicesQuery.data,
    content: contentQuery.data,
    isLoading: userQuery.isLoading || servicesQuery.isLoading || contentQuery.isLoading
  };
};
```

**hooks/useNotifications.ts** (v5에서 onSuccess 제거됨 → useEffect 패턴):
```ts
import { useQuery } from '@tanstack/react-query';
import { useEffect } from 'react';
import { fetchNotifications } from '@/services/mockApi';
import { useNotificationStore } from '@/store/useNotificationStore';

export const useNotifications = () => {
  const setNotifications = useNotificationStore((state) => state.setNotifications);
  const query = useQuery({ queryKey: ['notifications'], queryFn: fetchNotifications });

  useEffect(() => {
    if (query.data) {
      setNotifications(query.data);
    }
  }, [query.data, setNotifications]);

  return query;
};
```

