import { useEffect, useRef } from 'react';
import { Animated, View } from 'react-native';

export const SkeletonBox = ({ width, height, borderRadius = 8, className = '' }) => {
  const opacity = useRef(new Animated.Value(0.3)).current;

  useEffect(() => {
    Animated.loop(
      Animated.sequence([
        Animated.timing(opacity, { toValue: 0.7, duration: 800, useNativeDriver: true }),
        Animated.timing(opacity, { toValue: 0.3, duration: 800, useNativeDriver: true })
      ])
    ).start();
  }, []);

  return (
    <Animated.View
      style={{ width, height, borderRadius, opacity }}
      className={`bg-gray-200 ${className}`}
    />
  );
};
```

**NotificationBanner**:
```tsx
import { Animated } from 'react-native';
import { Ionicons } from '@expo/vector-icons';

export const NotificationBanner = ({ notification, onDismiss }) => {
  const slideAnim = useRef(new Animated.Value(0)).current;

  const dismiss = () => {
    Animated.timing(slideAnim, {
      toValue: -100,
      duration: 300,
      useNativeDriver: true
    }).start(() => onDismiss(notification.id));
  };

  return (
    <Animated.View style={{ transform: [{ translateY: slideAnim }] }}
      className="bg-blue-50 border-l-4 border-blue-500 flex-row items-center px-4 py-3 mx-4 my-2 rounded-lg">
      <Ionicons name="information-circle" size={24} color="#007AFF" />
      <Text className="flex-1 ml-3">{notification.title}</Text>
      {notification.isDismissable && (
        <TouchableOpacity onPress={dismiss}>
          <Ionicons name="close" size={20} color="#8E8E93" />
        </TouchableOpacity>
      )}
    </Animated.View>
  );
};
```

**SegmentTabs** (언더라인 애니메이션):
```tsx
export const SegmentTabs = ({ tabs, activeTab, onTabChange, variant = 'underline' }) => {
  const underlinePosition = useRef(new Animated.Value(0)).current;

  useEffect(() => {
    const index = tabs.indexOf(activeTab);
    Animated.spring(underlinePosition, {
      toValue: index * (screenWidth / tabs.length),
      useNativeDriver: true
    }).start();
  }, [activeTab]);

  return (
    <View className="flex-row border-b border-gray-200">
      {tabs.map((tab) => (
        <TouchableOpacity key={tab} onPress={() => onTabChange(tab)} className="flex-1 py-3">
          <Text className={activeTab === tab ? 'text-primary font-semibold' : 'text-gray-500'}>
            {tab}
          </Text>
        </TouchableOpacity>
      ))}
      <Animated.View
        style={{ transform: [{ translateX: underlinePosition }] }}
        className="absolute bottom-0 h-0.5 bg-primary"
      />
    </View>
  );
};
```

